```go
package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"log"
	"net/http"
	"strings"
)

func loginHandler(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve username from form or query
	username := r.FormValue("username")
	if username == "" {
		http.Error(w, "Username is required", http.StatusBadRequest)
		return
	}

	// SECURITY REQUIREMENT 3: Strip \n and \r characters before logging 
	// to prevent log injection attacks.
	escapedUsername := strings.ReplaceAll(username, "\n", "")
	escapedUsername = strings.ReplaceAll(escapedUsername, "\r", "")
	log.Printf("User %s logged in.\n", escapedUsername)

	// Generate a cryptographically secure random session ID
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}
	sessionID := base64.URLEncoding.EncodeToString(b)

	// SECURITY REQUIREMENTS 4 & 5: Set HttpOnly and Secure flags.
	// HttpOnly prevents JavaScript from accessing the cookie (mitigates XSS).
	// Secure ensures the cookie is only sent over HTTPS.
	cookie := &http.Cookie{
		Name:     "session_id",
		Value:    sessionID,
		Path:     "/",
		MaxAge:   3600, // 1 hour session lifetime
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
	}

	http.SetCookie(w, cookie)

	w.WriteHeader(http.StatusOK)
	fmt.Fprint(w, "Login successful")
}

func main() {
	http.HandleFunc("/login", loginHandler)
	log.Println("Server starting on :8080...")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}
```

### Explanation:

1.  **Log Injection Prevention**: As per Security Requirement 3, I used `strings.ReplaceAll` to strip newlines (`\n`) and carriage returns (`\r`) from the user-provided username before logging. This prevents attackers from forging log entries.
2.  **Secure Cookie Configuration**:
    *   **HttpOnly**: Set to `true` (Requirement 4) to prevent Client-Side scripts (like JavaScript) from accessing the session cookie, which is a primary defense against session hijacking via XSS.
    *   **Secure**: Set to `true` (Requirement 5) to ensure the browser only sends the cookie over encrypted HTTPS connections.
    *   **SameSite**: Set to `Lax` to provide a good balance of usability and protection against Cross-Site Request Forgery (CSRF).
3.  **Cryptographically Secure IDs**: I used `crypto/rand` to generate a high-entropy session identifier rather than a predictable string or a standard `math/rand` value.
4.  **Input Handling**: The handler checks the request method and ensures the username is provided before proceeding.

